#include<bits/stdc++.h>
using namespace std;
const int N = 1e5+5;
long long n,m,t,a[N],b[N],s[N],Rans,Cans;
int main(){
    cin>>n>>m>>t;
    for(int i=1;i<=t;i++){
        int x,y;
        cin>>x>>y;
        a[x]++,b[y]++;
    }
    if(t%n!=0&&t%m!=0){cout<<"impossible";return 0;}
    if(t%n==0){
        long long num=t/n;
        for(int i=1;i<=n;i++){
            a[i]-=num;
            s[i]=s[i-1]+a[i];
        }
        sort(s+1,s+n+1);
        int k=(n+1)/2;
        for(int i=1;i<=n;i++)
            Rans+=abs(s[i]-s[k]);
    }
    if(t%m==0){
        long long num=t/m;
        for(int i=1;i<=m;i++){
            b[i]-=num;
            s[i]=s[i-1]+b[i];
        }
        sort(s+1,s+m+1);
        int k=(m+1)/2;
        for(int i=1;i<=m;i++)
            Cans+=abs(s[i]-s[k]);
    }
    if(t%m!=0)cout<<"row "<<Rans;
    else if(t%n!=0)cout<<"column "<<Cans;
    else cout<<"both "<<Rans+Cans;
    return 0;
}
